mapper.select:
select distinct
from sys_menu m left join sys_role_menu rm on m.menu_id = rm.menu_id left join sys_user_role ur on rm.role_id = ur.role_id where (m.is_protected = 0 or ur.user_id = #{userId})
and is_visible = #{visible}
and m.menu_name like concat('%', #{menuName}, '%')
and m.menu_status = #{menuStatus}
order by m.parent_id, m.menu_order
